const raw = $json.content && $json.content[0] ? $json.content[0].text.trim() : '';

const clean = raw.startsWith('```')
  ? raw.replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '').trim()
  : raw;

let spec;
try {
  spec = JSON.parse(clean);
} catch (e) {
  throw new Error('Claude returned invalid JSON. Raw: ' + raw.slice(0, 300));
}

if (!spec.title || !spec.type || !spec.description) {
  throw new Error('Spec missing required fields. Got keys: ' + Object.keys(spec).join(', '));
}

const opportunity = $('Webhook Trigger').item.json.record;

return [{
  json: {
    title: spec.title,
    type: spec.type,
    description: spec.description,
    suggested_price_usd: spec.suggested_price_usd || 0,
    target_keywords: spec.target_keywords || [],
    spec: spec.spec || {},
    opportunity_id: opportunity.id,
    opportunity_niche: opportunity.niche,
    opportunity_etsy_search: opportunity.etsy_search
  }
}];

const p = $('Parse Product Spec').item.json;
const fileUrl = $('Build Product File').item.json.file_url || null;
const spec = p.spec || {};

let specRows = '';
if (p.type === 'spreadsheet' && spec.tabs) {
  specRows += '<h3 style="color:#C8F53A;margin:16px 0 8px;font-family:sans-serif">Tabs (' + spec.tabs.length + ')</h3>';
  specRows += '<ul style="margin:0;padding-left:20px;font-family:sans-serif">';
  spec.tabs.forEach(function(t) {
    specRows += '<li><strong>' + t.name + '</strong> — ' + t.purpose + '</li>';
  });
  specRows += '</ul>';
  if (spec.dashboard && spec.dashboard.kpis) {
    specRows += '<h3 style="color:#C8F53A;margin:16px 0 8px;font-family:sans-serif">Dashboard KPIs</h3>';
    specRows += '<ul style="margin:0;padding-left:20px;font-family:sans-serif">';
    spec.dashboard.kpis.forEach(function(k) { specRows += '<li>' + k + '</li>'; });
    specRows += '</ul>';
  }
} else if (p.type === 'notion' && spec.databases) {
  specRows += '<h3 style="color:#C8F53A;margin:16px 0 8px;font-family:sans-serif">Databases (' + spec.databases.length + ')</h3>';
  specRows += '<ul style="margin:0;padding-left:20px;font-family:sans-serif">';
  spec.databases.forEach(function(d) {
    const propCount = (d.properties || []).length;
    const viewCount = (d.views || []).length;
    specRows += '<li><strong>' + d.name + '</strong> — ' + propCount + ' properties, ' + viewCount + ' views</li>';
  });
  specRows += '</ul>';
} else if (p.type === 'document-bundle' && spec.documents) {
  specRows += '<h3 style="color:#C8F53A;margin:16px 0 8px;font-family:sans-serif">Documents (' + spec.documents.length + ')</h3>';
  specRows += '<ul style="margin:0;padding-left:20px;font-family:sans-serif">';
  spec.documents.forEach(function(d) {
    specRows += '<li><strong>' + d.name + '</strong> — ' + (d.sections || []).length + ' sections</li>';
  });
  specRows += '</ul>';
}

const keywords = (p.target_keywords || []).map(function(k) {
  return '<span style="background:#C8F53A;color:#0A0A0A;padding:2px 8px;border-radius:4px;margin:2px;display:inline-block;font-size:12px;font-family:sans-serif">' + k + '</span>';
}).join(' ');

const dateStr = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const typeLabel = (p.type || '').toUpperCase().replace(/-/g, ' ');
const price = typeof p.suggested_price_usd === 'number' ? p.suggested_price_usd.toFixed(2) : p.suggested_price_usd;

const html = '<!DOCTYPE html><html><body style="font-family:sans-serif;background:#0A0A0A;color:#fff;margin:0;padding:0">'
  + '<div style="max-width:640px;margin:0 auto;padding:32px 24px">'
  + '<p style="color:#C8F53A;font-size:12px;letter-spacing:2px;margin:0 0 8px">CIPHER STUDIO</p>'
  + '<h1 style="font-size:32px;color:#fff;margin:0 0 4px">New Product Spec Ready</h1>'
  + '<p style="color:#666;margin:0 0 32px;font-size:14px">' + dateStr + '</p>'
  + '<div style="background:#111;border:1px solid #222;border-radius:8px;padding:24px;margin-bottom:24px">'
  + '<p style="color:#C8F53A;font-size:11px;letter-spacing:1px;margin:0 0 8px">' + typeLabel + '</p>'
  + '<h2 style="margin:0 0 12px;font-size:22px">' + p.title + '</h2>'
  + '<p style="color:#aaa;margin:0 0 16px;line-height:1.6">' + p.description + '</p>'
  + '<p style="margin:0"><strong style="color:#C8F53A">Suggested Price:</strong> $' + price + '</p>'
  + '</div>'
  + (specRows ? '<div style="background:#111;border:1px solid #222;border-radius:8px;padding:24px;margin-bottom:24px">' + specRows + '</div>' : '')
  + '<div style="background:#111;border:1px solid #222;border-radius:8px;padding:24px;margin-bottom:24px">'
  + '<h3 style="color:#C8F53A;margin:0 0 12px">Target Keywords</h3>'
  + '<div>' + keywords + '</div>'
  + '</div>'
  + (fileUrl ? '<div style="background:#111;border:1px solid #C8F53A;border-radius:8px;padding:20px;margin-bottom:24px;text-align:center"><p style="color:#C8F53A;font-size:11px;letter-spacing:1px;margin:0 0 8px">FILE READY</p><a href="' + fileUrl + '" style="background:#C8F53A;color:#0A0A0A;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;font-size:14px">Download .xlsx</a></div>' : '')
  + '<p style="color:#444;font-size:12px;text-align:center">Review the full spec in Supabase &rarr; products table &nbsp;&middot;&nbsp; cipherstudio.co</p>'
  + '</div></body></html>';

return [{ json: {
  subject: 'New Product Spec: ' + p.title + ' (' + p.type + ')',
  html: html
} }];
